package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.sql.*;import java.time.*;import java.util.*;public class AdmissionServiceImpl implements AdmissionService{private static final Logger LOG=LoggerFactory.getLogger(AdmissionServiceImpl.class);private final AdmissionDao admissions;private final BedDao beds;private final PatientDao patients;private final DoctorDao doctors;private final AdmissionValidator validator;private final AdmissionNumberGenerator numbers;private final AdmissionChargeCalculator charges;private final AuditLogDao audit;public AdmissionServiceImpl(){this(new AdmissionDaoImpl(),new BedDaoImpl(),new PatientDaoImpl(),new DoctorDaoImpl(),new AdmissionValidator(),new AdmissionNumberGenerator(),new AdmissionChargeCalculator(),new AuditLogDaoImpl());}public AdmissionServiceImpl(AdmissionDao a,BedDao b,PatientDao p,DoctorDao d,AdmissionValidator v,AdmissionNumberGenerator n,AdmissionChargeCalculator c,AuditLogDao l){admissions=a;beds=b;patients=p;doctors=d;validator=v;numbers=n;charges=c;audit=l;}public Page<Admission>listAdmissions(PageRequest p,Long pi,Long di,Long dep,Long room,LocalDate f,LocalDate t,String st,AuthenticatedUser u){try{if(u==null)return empty(p);if("PATIENT".equals(u.getRoleName())){Patient x=patient(u);if(x==null)return empty(p);pi=x.getPatientId();}else if("DOCTOR".equals(u.getRoleName())){Doctor x=doctor(u);if(x==null)return empty(p);di=x.getDoctorId();}else if(!Set.of("ADMIN","RECEPTIONIST","NURSE","BILLING_STAFF").contains(u.getRoleName()))return empty(p);return admissions.findAll(p,pi,di,dep,room,f,t,st);}catch(Exception e){LOG.error("Admission listing failed",e);return empty(p);}}public Optional<Admission>getAdmission(Long id,AuthenticatedUser u){try{return admissions.findById(id).filter(a->view(a,u));}catch(Exception e){return Optional.empty();}}public ServiceResult<Long>admitPatient(AdmissionForm f,AuditContext a,AuthenticatedUser u){if(!manage(u))return failL(ServiceResult.Status.FORBIDDEN,"Admission access denied");ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Patient p=patients.findById(f.getPatientId()).orElse(null);Doctor d=doctors.findById(f.getDoctorId()).orElse(null);if(p==null||!"ACTIVE".equals(p.getStatus()))return failL(ServiceResult.Status.CONFLICT,"Patient is not active");if(d==null||!"ACTIVE".equals(d.getStatus())||!f.getDepartmentId().equals(d.getDepartmentId()))return failL(ServiceResult.Status.CONFLICT,"Doctor and department are invalid");long id=tx(c->{Bed b=beds.lockById(c,f.getBedId()).orElse(null);if(b==null||!"AVAILABLE".equals(b.getStatus()))throw new Business("Selected bed is unavailable");if(admissions.existsActiveAdmissionForPatient(f.getPatientId()))throw new Business("Patient already has an active admission");Admission x=from(f);x.setAdmissionNumber(numbers.next(c));x.setCreatedBy(u.getUserId());x.setStatus("ADMITTED");long z=admissions.create(c,x);beds.updateStatus(c,b.getBedId(),"OCCUPIED");return z;});event("ADMISSION_CREATED",id,a);return ServiceResult.success("Patient admitted",id);}catch(Business e){event("ADMISSION_CREATION_BLOCKED",null,a);return failL(ServiceResult.Status.CONFLICT,e.getMessage());}catch(Exception e){LOG.error("Admission creation failed",e);return failL(ServiceResult.Status.SYSTEM_ERROR,"Admission service unavailable");}}public ServiceResult<Void>updateAdmission(AdmissionForm f,AuditContext a,AuthenticatedUser u){if(!manage(u))return fail(ServiceResult.Status.FORBIDDEN,"Admission access denied");ValidationResult v=validator.validate(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{Admission old=admissions.findById(f.getAdmissionId()).orElse(null);if(old==null||!active(old))return fail(ServiceResult.Status.CONFLICT,"Admission is not active");Admission x=from(f);x.setAdmissionId(old.getAdmissionId());tx(c->{admissions.updateActiveAdmission(c,x);return null;});event("ADMISSION_UPDATED",x.getAdmissionId(),a);return ServiceResult.success("Admission updated",null);}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Admission service unavailable");}}public ServiceResult<Void>transferPatient(AdmissionTransferForm f,AuditContext a,AuthenticatedUser u){if(!manage(u))return fail(ServiceResult.Status.FORBIDDEN,"Admission access denied");ValidationResult v=validator.validateTransfer(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{tx(c->{Admission x=admissions.lockById(c,f.getAdmissionId()).orElse(null);if(x==null||!active(x))throw new Business("Admission is not active");if(x.getBedId().equals(f.getTargetBedId()))throw new Business("Select a different bed");Bed current=beds.lockById(c,x.getBedId()).orElseThrow(()->new Business("Current bed not found"));Bed target=beds.lockById(c,f.getTargetBedId()).orElseThrow(()->new Business("Target bed not found"));if(!"AVAILABLE".equals(target.getStatus()))throw new Business("Target bed is unavailable");beds.updateStatus(c,current.getBedId(),"AVAILABLE");beds.updateStatus(c,target.getBedId(),"OCCUPIED");admissions.transferBed(c,x.getAdmissionId(),target.getBedId(),"ADMITTED");admissions.recordTransfer(c,x.getAdmissionId(),current.getBedId(),target.getBedId(),f.getTransferReason().trim(),u.getUserId());return null;});event("ADMISSION_TRANSFERRED",f.getAdmissionId(),a);return ServiceResult.success("Patient transferred",null);}catch(Business e){event("ADMISSION_TRANSFER_BLOCKED",f.getAdmissionId(),a);return fail(ServiceResult.Status.CONFLICT,e.getMessage());}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Admission service unavailable");}}public ServiceResult<Void>dischargePatient(DischargeForm f,AuditContext a,AuthenticatedUser u){if(!manage(u))return fail(ServiceResult.Status.FORBIDDEN,"Admission access denied");ValidationResult v=validator.validateDischarge(f);if(v.hasErrors())return ServiceResult.failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v.getErrors());try{tx(c->{Admission x=admissions.lockById(c,f.getAdmissionId()).orElse(null);if(x==null||!active(x))throw new Business("Admission is not active");Bed b=beds.lockById(c,x.getBedId()).orElseThrow(()->new Business("Assigned bed not found"));LocalDateTime now=LocalDateTime.now();charges.calculateRoomCharge(x.getAdmissionDate(),now,b.getDailyRate());admissions.discharge(c,x.getAdmissionId(),now,f.getDischargeSummary().trim(),"DISCHARGED");beds.updateStatus(c,b.getBedId(),"AVAILABLE");return null;});event("ADMISSION_DISCHARGED",f.getAdmissionId(),a);return ServiceResult.success("Patient discharged",null);}catch(Business e){event("ADMISSION_DISCHARGE_BLOCKED",f.getAdmissionId(),a);return fail(ServiceResult.Status.CONFLICT,e.getMessage());}catch(Exception e){return fail(ServiceResult.Status.SYSTEM_ERROR,"Admission service unavailable");}}public ServiceResult<Void>cancelAdmission(Long id,AuditContext a,AuthenticatedUser u){if(!manage(u))return fail(ServiceResult.Status.FORBIDDEN,"Admission access denied");try{tx(c->{Admission x=admissions.lockById(c,id).orElse(null);if(x==null||!active(x))throw new Business("Admission is not active");Bed b=beds.lockById(c,x.getBedId()).orElseThrow();admissions.cancel(c,id,"CANCELLED");beds.updateStatus(c,b.getBedId(),"AVAILABLE");return null;});event("ADMISSION_CANCELLED",id,a);return ServiceResult.success("Admission cancelled",null);}catch(Exception e){return fail(ServiceResult.Status.CONFLICT,"Admission could not be cancelled");}}private Admission from(AdmissionForm f){Admission a=new Admission();a.setPatientId(f.getPatientId());a.setDoctorId(f.getDoctorId());a.setDepartmentId(f.getDepartmentId());a.setAppointmentId(f.getAppointmentId());a.setBedId(f.getBedId());a.setExpectedDischargeDate(f.getExpectedDischargeDate()==null||f.getExpectedDischargeDate().isBlank()?null:LocalDate.parse(f.getExpectedDischargeDate()));a.setAdmissionReason(f.getAdmissionReason().trim());return a;}private boolean manage(AuthenticatedUser u){return u!=null&&Set.of("ADMIN","RECEPTIONIST").contains(u.getRoleName());}private boolean view(Admission a,AuthenticatedUser u){if(u==null)return false;if(Set.of("ADMIN","RECEPTIONIST","NURSE","BILLING_STAFF").contains(u.getRoleName()))return true;if("PATIENT".equals(u.getRoleName())){Patient p=patient(u);return p!=null&&p.getPatientId().equals(a.getPatientId());}if("DOCTOR".equals(u.getRoleName())){Doctor d=doctor(u);return d!=null&&d.getDoctorId().equals(a.getDoctorId());}return false;}private boolean active(Admission a){return Set.of("ADMITTED","TRANSFERRED").contains(a.getStatus());}private Patient patient(AuthenticatedUser u){try{return patients.findAll(new PageRequest(1,100,u.getUsername()),"ACTIVE").getContent().stream().filter(p->u.getUserId().equals(p.getUserId())).findFirst().orElse(null);}catch(Exception e){return null;}}private Doctor doctor(AuthenticatedUser u){try{return doctors.findByUserId(u.getUserId()).orElse(null);}catch(Exception e){return null;}}private<T>T tx(Work<T>w)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){boolean old=c.getAutoCommit();c.setAutoCommit(false);try{T x=w.run(c);c.commit();return x;}catch(Exception e){c.rollback();if(e instanceof SQLException s)throw s;if(e instanceof RuntimeException r)throw r;throw new SQLException(e);}finally{c.setAutoCommit(old);}}}private interface Work<T>{T run(Connection c)throws Exception;}private void event(String e,Long id,AuditContext a){try{audit.recordEvent(e,a==null?null:a.userId(),"ADMISSION",id,a==null?null:a.ipAddress(),a==null?null:a.userAgent());}catch(Exception ignored){}}private Page<Admission>empty(PageRequest p){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private static class Business extends RuntimeException{Business(String m){super(m);}}}
